class Solution:
    def maximumSumQueries(self, nums1: List[int], nums2: List[int], queries: List[List[int]]) -> List[int]:
        import bisect

        n = len(nums1)
        pairs = sorted([(nums1[i], nums2[i]) for i in range(n)], key=lambda x: (x[0], x[1]))
        queries_sorted = sorted([(x, y, i) for i, (x, y) in enumerate(queries)]), key=lambda x: (x[0], x[1]))

        # Preprocess to build a structure for efficient querying
        max_sums = []
        res = [-1] * len(queries)
        idx = 0

        for x, y, i in queries_sorted:
            while idx < n and pairs[idx][0] < x:
                idx += 1
            max_sum = -1
            for j in range(idx, n):
                if pairs[j][1] >= y:
                    max_sum = max(max_sum, pairs[j][0] + pairs[j][1])
            res[i] = max_sum

        return res
